import { Component, OnInit } from "@angular/core";
import { HttpClient } from "@angular/common/http";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from "@angular/forms";
import { AlertController } from "@ionic/angular";
import { AlertService } from "src/app/core/services/alert.service";
import { EnvService } from "src/app/core/services/env.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { sortingService } from "src/app/core/services/sorting.service";
import { format, getMonth, parse } from "date-fns";
import { TranslateService } from "@ngx-translate/core";
import { IBusinessDivisions } from "src/app/views/Models/References/BusinessDivisions";
import { IBusinessDivisionsActivityTypes } from "src/app/views/Models/References/BusinessDivisionsType";
import { IBusinessDivisionsActivitySpec } from "src/app/views/Models/References/BusinessDivisionsSpec";
import { IBusinessAll } from "src/app/views/Models/References/BusinessAll";
import { ReferencesService } from "src/app/core/services/references.service";
import { Node, Tree } from "src/app/views/Models/Users/Tree";
@Component({
  selector: "app-labor-sector-manage",
  templateUrl: "./labor-sector-manage.page.html",
  styleUrls: ["./labor-sector-manage.page.scss"],
})
export class LaborSectorManagePage implements OnInit {
  showLoader: boolean = false;
  isInserting: boolean = false;
  isEditing: boolean = false;
  isSubmitted: boolean = false;
  TreeNodes: Tree<Node>[];
  currentTreeNode: Tree<Node>;

  hasSupervisor: boolean = false;
  FilteredBsDiv: IBusinessAll[];
  BsDivInfo: IBusinessAll;
  laborForm: FormGroup = this.formBuilder.group({
    tree_code: [""],
    tree_name: ["", [Validators.required]],
    active_rec: [""],
  });
  constructor(
    private formBuilder: FormBuilder,
    private http: HttpClient,
    private alertController: AlertController,
    private env: EnvService,
    private authService: MohassilAuthService,
    private sortingService: sortingService,
    private alertServices: AlertService,
    public translate: TranslateService,
    private ReferencesService: ReferencesService
  ) {}

  ngOnInit() {
    this.GetBsDiv1();
  }
  noWhitespaceValidator(control: FormControl) {
    const isWhitespace =
      control.value !== null &&
      (control.value || "").toString().trim().length === 0;
    const isValid = !isWhitespace;
    return isValid ? null : { whitespace: true };
  }
  GetBsDiv1() {
    this.showLoader = true;
    this.http
      .get<IBusinessAll[]>(
        this.env.API_URL + "api/Business/GetBusinessDivisions"
      )
      .subscribe({
        next: (bs_divs_1) => {
          this.TreeNodes = bs_divs_1.map((bs_div_1) => ({
            data: {
              org_code: bs_div_1.org_code,
              node_code: parseInt(bs_div_1.bs_div_1_code),
              active_rec: bs_div_1.active_rec,
              parent_id: null,
            },
            text: bs_div_1.bs_div_1_name,
            collapsed: true,
            canEdit: true,
            canDelete: true,
            canAdd: true,
            canSelect: false,
            initialized: false,
          }));
          this.http
            .get<IBusinessAll[]>(
              this.env.API_URL + "api/Business/GetBusinessActivityTypes"
            )
            .subscribe({
              next: (bs_divs_2) => {
                this.TreeNodes = this.TreeNodes.map<Tree<Node>>((treeNode) => ({
                  ...treeNode,
                  children: bs_divs_2
                    .filter(
                      (bs_div_2) =>
                        treeNode.data.node_code ==
                        parseInt(bs_div_2.bs_div_1_code)
                    )
                    .map<Tree<Node>>((bs_div_2) => ({
                      data: {
                        org_code: bs_div_2.org_code,
                        node_code: parseInt(bs_div_2.bs_div_2_code),
                        active_rec: bs_div_2.active_rec,
                        parent_id: parseInt(bs_div_2.bs_div_1_code),
                      },
                      text: bs_div_2.bs_div_2_name,
                      collapsed: true,
                      canEdit: true,
                      canDelete: true,
                      canAdd: true,
                      canSelect: false,
                      initialized: false,
                    })),
                }));
                this.http
                  .get<IBusinessAll[]>(
                    this.env.API_URL + "api/Business/GetBusinessSpecialities"
                  )
                  .subscribe({
                    next: (bs_divs_3) => {
                      this.TreeNodes = this.TreeNodes.map((treeNode) => ({
                        ...treeNode,
                        children: treeNode.children?.map((child) => ({
                          ...child,
                          children: bs_divs_3
                            .filter(
                              (bs_div_3) =>
                                child.data.node_code ==
                                  parseInt(bs_div_3.bs_div_2_code) &&
                                treeNode.data.node_code ==
                                  parseInt(bs_div_3.bs_div_1_code)
                            )
                            .map<Tree<Node>>((bs_div_3) => ({
                              data: {
                                org_code: bs_div_3.org_code,
                                node_code: parseInt(bs_div_3.bs_div_3_code),
                                active_rec: bs_div_3.active_rec,
                                parent_id: parseInt(bs_div_3.bs_div_2_code),
                              },
                              text: bs_div_3.bs_div_3_name,
                              collapsed: true,
                              canEdit: true,
                              canDelete: true,
                              canAdd: false,
                              canSelect: false,
                              initialized: false,
                            })),
                        })),
                      }));
                      this.showLoader = false;
                    },
                  });
              },
            });
        },
      });
  }
  Edit(node: Tree<Node>): void {
    this.hasSupervisor = false;
    this.currentTreeNode = node;
    if (node.data.parent_id == null && node.children) {
      this.GetBsDivByID(node.data.node_code, true);
    }
    if (node.data.parent_id != null && node.children) {
      this.GetBsDiv2ByID(node.data.parent_id, node.data.node_code, true);
    }
    if (node.data.parent_id != null && !node.children) {
      let rootNode = this.TreeNodes.find((rootNode) => {
        return rootNode.children?.find((nestedNodes) => {
          return nestedNodes.data.node_code == node.data.parent_id;
        });
      });
      this.GetBsDiv3ByID(
        rootNode.data.node_code,
        node.data.parent_id,
        node.data.node_code,
        true
      );
    }
  }

  Delete(node: Tree<Node>): void {
    if (node.data.parent_id == null && node.children) {
      this.GetBsDivByIDDelete(node.data.node_code);
    }
    if (node.data.parent_id != null && node.children) {
      this.GetBsDiv2ByIDDelete(node.data.parent_id, node.data.node_code);
    }
    if (node.data.parent_id != null && !node.children) {
      let rootNode = this.TreeNodes.find((rootNode) => {
        return rootNode.children?.find((nestedNodes) => {
          return nestedNodes.data.node_code == node.data.parent_id;
        });
      });
      this.GetBsDiv3ByIDDelete(
        rootNode.data.node_code,
        node.data.parent_id,
        node.data.node_code
      );
    }
  }

  Add(node: Tree<Node>): void {
    this.currentTreeNode = node;
    if (node.data.parent_id == null && node.children) {
      this.GetBsDiv1Insert(node.data.node_code, true);
    }
    if (node.data.parent_id != null && node.children) {
      this.GetBsDiv2Insert(node.data.parent_id, node.data.node_code, true);
    }

    this.isInserting = this.isInserting;
    this.showLoader = false;
    this.hasSupervisor = true;
  }
  BsDivInsert() {
    this.isInserting = true;
    this.showLoader = false;
    this.laborForm.patchValue({
      tree_name: "",
      tree_code: "",
      active_rec: 0,
    });
  }
  async GetBsDiv1Insert(bs_div_1_code, isInserting) {
    if (isInserting) this.BsDiv1Insert(bs_div_1_code);
    this.isInserting = isInserting;
    this.showLoader = false;
  }
  BsDiv1Insert(bs_div_1_code) {
    this.laborForm.patchValue({
      tree_name: " ",
      tree_code: bs_div_1_code,
      active_rec: 0,
    });
  }
  async GetBsDiv2Insert(bs_div_1_code, bs_div_2_code, isInserting) {
    if (isInserting) this.BsDiv2Insert(bs_div_1_code, bs_div_2_code);
    this.isInserting = isInserting;
    this.showLoader = false;
  }
  BsDiv2Insert(bs_div_1_code, bs_div_2_code) {
    this.laborForm.patchValue({
      tree_name: " ",
      tree_code: bs_div_1_code,
      active_rec: 0,
      parent_id: bs_div_2_code,
    });
  }

  async GetBsDivByID(bs_div_1_code, isEditing) {
    this.http
      .get<IBusinessAll>(
        `${this.env.API_URL}api/Business/GetBusinessDivisionsByCode?bs_div_1_code=${bs_div_1_code}`
      )

      .subscribe({
        next: (data) => {
          this.BsDivInfo = data;
          if (isEditing) this.patchDataValue();
          this.isEditing = isEditing;
          this.showLoader = false;
        },

        error: (err) => {
          console.log(err);
          this.showLoader = false;
        },
      });
  }

  GetBsDiv2ByID(bs_div_1_code, bs_div_2_code, isEditing) {
    this.http
      .get<IBusinessAll>(
        `${this.env.API_URL}api/Business/GetBusinessActivityTypesByCode?bs_div_1_code=${bs_div_1_code}&bs_div_2_code=${bs_div_2_code}`
      )

      .subscribe({
        next: (data) => {
          this.BsDivInfo = data;
          if (isEditing) this.GetAllSupervisors();
          this.isEditing = isEditing;
          this.showLoader = false;
        },

        error: (err) => {
          console.log(err);
          this.showLoader = false;
        },
      });
  }
  GetBsDiv3ByID(bs_div_1_code, bs_div_2_code, bs_div_3_code, isEditing) {
    this.http
      .get<IBusinessAll>(
        `${this.env.API_URL}api/Business/GetBusinessSpecialitiesByCode?bs_div_1_code=${bs_div_1_code}&bs_div_2_code=${bs_div_2_code}&bs_div_3_code=${bs_div_3_code}`
      )

      .subscribe({
        next: (data) => {
          this.BsDivInfo = data;
          if (isEditing) this.GetAllChild();
          this.isEditing = isEditing;
          this.showLoader = false;
        },

        error: (err) => {
          console.log(err);
          this.showLoader = false;
        },
      });
  }
  patchDataValue() {
    this.laborForm.patchValue({
      tree_name: this.BsDivInfo[0].bs_div_1_name,
      tree_code: this.BsDivInfo[0].bs_div_1_code,
      active_rec: this.BsDivInfo[0].active_rec,
    });
  }
  GetAllSupervisors() {
    this.laborForm.patchValue({
      tree_name: this.BsDivInfo[0].bs_div_2_name,
      tree_code: this.BsDivInfo[0].bs_div_2_code,
      active_rec: this.BsDivInfo[0].active_rec,
    });
  }
  GetAllChild() {
    this.laborForm.patchValue({
      tree_name: this.BsDivInfo[0].bs_div_3_name,
      tree_code: this.BsDivInfo[0].bs_div_3_code,
      active_rec: this.BsDivInfo[0].active_rec,
    });
  }
  async GetBsDivByIDDelete(bs_div_1_code) {
    if (
      await this.alertServices.DeleteAlert("هل انت متاكد من مسح هذه الوظيفة؟")
    ) {
      this.showLoader = true;
      this.http
        .post(this.env.API_URL + "api/Business/GetBusinessDivisionsDelete", {
          bs_div_1_code: bs_div_1_code.toString(),
        })
        .subscribe({
          next: (data) => {
            this.showLoader = false;
            this.alertServices.showAlertConfirm("تم الحذف بنجاح", true);
          },
          error: (err) => {
            console.log(err);
            this.alertServices.showAlertError(err.error, false);
            this.showLoader = false;
          },
        });
    }
  }
  async GetBsDiv2ByIDDelete(bs_div_1_code, bs_div_2_code) {
    if (
      await this.alertServices.DeleteAlert("هل انت متاكد من مسح هذه الوظيفة؟")
    ) {
      this.showLoader = true;
      this.http
        .post(this.env.API_URL + "api/Business/GetBusinessActivityTypeDelete", {
          bs_div_1_code: bs_div_1_code.toString(),
          bs_div_2_code: bs_div_2_code.toString(),
        })
        .subscribe({
          next: (data) => {
            this.showLoader = false;
            this.alertServices.showAlertConfirm("تم الحذف بنجاح", true);
          },
          error: (err) => {
            console.log(err);
            this.alertServices.showAlertError(err.error, false);
            this.showLoader = false;
          },
        });
    }
  }
  async GetBsDiv3ByIDDelete(bs_div_1_code, bs_div_2_code, bs_div_3_code) {
    if (
      await this.alertServices.DeleteAlert("هل انت متاكد من مسح هذه الوظيفة؟")
    ) {
      this.showLoader = true;
      console.log(bs_div_1_code, bs_div_2_code, bs_div_3_code);
      this.http
        .post(this.env.API_URL + "api/Business/GetBusinessSpecialitiesDelete", {
          bs_div_1_code: bs_div_1_code.toString(),
          bs_div_2_code: bs_div_2_code.toString(),
          bs_div_3_code: bs_div_3_code.toString(),
        })
        .subscribe({
          next: (data) => {
            this.showLoader = false;
            this.alertServices.showAlertConfirm("تم الحذف بنجاح", true);
          },
          error: (err) => {
            console.log(err);
            this.alertServices.showAlertError(err.error, false);
            this.showLoader = false;
          },
        });
    }
  }
  clearForms() {
    this.isInserting = false;
    this.isEditing = false;
    this.laborForm.reset();
  }
  async Insertbs() {
    let node: Tree<Node> = this.currentTreeNode;
    if (
      node == undefined &&
      (await this.alertServices.SaveAlert("هل تريد الاضافة؟"))
    ) {
      this.http
        .post(this.env.API_URL + "api/Business/GetBusinessDivisionsInsert", {
          bs_div_1_name: this.laborForm.value.tree_name.toString(),
          active_rec: this.laborForm.value.active_rec == 1 ? 1 : 0,
        })
        .subscribe({
          next: (data) => {
            this.showLoader = false;
            this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
          },
          error: (err) => {
            console.log(err);
            this.alertServices.showAlertError(err.error, false);
            this.showLoader = false;
          },
        });
    }
    if (this.laborForm.valid) {
      if (await this.alertServices.SaveAlert("هل تريد الاضافة؟")) {
        this.showLoader = true;
        if (node.data.parent_id == null) {
          this.http
            .post(
              this.env.API_URL + "api/Business/GetBusinessActivityTypesInsert",
              {
                bs_div_1_code: node.data.node_code.toString(),
                bs_div_2_name: this.laborForm.value.tree_name.toString(),
                active_rec: this.laborForm.value.active_rec == 1 ? 1 : 0,
              }
            )
            .subscribe({
              next: (data) => {
                this.showLoader = false;
                this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
              },
              error: (err) => {
                console.log(err);
                this.alertServices.showAlertError(err.error, false);
                this.showLoader = false;
              },
            });
        }
        if (node.data.parent_id != null) {
          this.http
            .post(
              this.env.API_URL + "api/Business/GetBusinessSpecialitiesInsert",
              {
                bs_div_1_code: node.data.parent_id.toString(),
                bs_div_2_code: node.data.node_code.toString(),
                bs_div_3_name: this.laborForm.value.tree_name.toString(),
                active_rec: this.laborForm.value.active_rec == 1 ? 1 : 0,
              }
            )
            .subscribe({
              next: (data) => {
                this.showLoader = false;
                this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
              },
              error: (err) => {
                console.log(err);
                this.alertServices.showAlertError(err.error, false);
                this.showLoader = false;
              },
            });
        }
      }
    } else {
      this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
    }
  }
  async Editbs() {
    let node: Tree<Node> = this.currentTreeNode;
    if (this.laborForm.valid) {
      if (await this.alertServices.SaveAlert("هل تريد تعديل البيانات؟"))
        if (node.data.parent_id == null && node.children) {
          this.showLoader = true;
          this.http
            .post(
              this.env.API_URL + "api/Business/GetBusinessDivisionsUpdate",
              {
                bs_div_1_code: node.data.node_code.toString(),
                bs_div_1_name: this.laborForm.value.tree_name.toString(),
                active_rec: this.laborForm.value.active_rec == 1 ? 1 : 0,
              }
            )
            .subscribe({
              next: (data) => {
                this.showLoader = false;
                this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
              },
              error: (err) => {
                console.log(err);
                this.alertServices.showAlertError(err.error, false);
                this.showLoader = false;
              },
            });
        }
      if (node.data.parent_id != null && node.children) {
        this.showLoader = true;
        this.http
          .post(
            this.env.API_URL + "api/Business/GetBusinessActivityTypesUpdate",
            {
              bs_div_1_code: node.data.parent_id.toString(),
              bs_div_2_code: node.data.node_code.toString(),
              bs_div_2_name: this.laborForm.value.tree_name.toString(),
              active_rec: this.laborForm.value.active_rec == 1 ? 1 : 0,
            }
          )
          .subscribe({
            next: (data) => {
              this.showLoader = false;
              this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
            },
            error: (err) => {
              console.log(err);
              this.alertServices.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
      }
      if (node.data.parent_id != null && !node.children) {
        this.showLoader = true;
        let rootNode = this.TreeNodes.find((rootNode) => {
          return rootNode.children?.find((nestedNodes) => {
            return nestedNodes.data.node_code == node.data.parent_id;
          });
        });
        this.http
          .post(
            this.env.API_URL + "api/Business/GetBusinessSpecialitiesUpdate",
            {
              bs_div_1_code: rootNode.data.node_code.toString(),
              bs_div_2_code: node.data.parent_id.toString(),
              bs_div_3_code: node.data.node_code.toString(),
              bs_div_3_name: this.laborForm.value.tree_name.toString(),
              active_rec: this.laborForm.value.active_rec == 1 ? 1 : 0,
            }
          )
          .subscribe({
            next: (data) => {
              this.showLoader = false;
              this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
            },
            error: (err) => {
              console.log(err);
              this.alertServices.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
      }
    } else {
      this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
    }
  }
}
